Another idea I've been kicking around, but not sure how I feel about it just yet... grouping functionality together more. Something like:

```c#
public abstract class Workspace
{
    // ...

    public abstract WorkspaceConfig Config { get; }
    public abstract WorkspaceStacks Stacks { get; }
    public abstract WorkspacePlugins Plugins { get; }

    // ...
}

public abstract class WorkspaceConfig
{
    public abstract Task<ConfigValue> GetAsync(string stackName, string key);
    public abstract Task<ImmutableDictionary<string, ConfigValue>> GetAllAsync(string stackName);

    public abstract Task SetAsync(string stackName, string key, ConfigValue value);
    public abstract Task SetAllAsync(string stackName, IDictionary<string, ConfigValue> configMap);

    public abstract Task RemoveAsync(string stackName, string key);
    public abstract Task RemoveAllAsync(string stackName, IEnumerable<string> keys);

    public abstract Task<ImmutableDictionary<string, ConfigValue>> RefreshAsync(string stackName);
}

public abstract class WorkspaceStacks
{
    public abstract Task<StackInfo?> GetSelectedAsync();
    public abstract Task CreateAsync(string stackName);
    public abstract Task SelectAsync(string stackName);
    public abstract Task RemoveAsync(string stackName);
    public abstract Task<ImmutableList<StackInfo>> ListAsync();
}

public abstract class WorkspacePlugins
{
    public abstract Task InstallAsync(string name, string version, string? kind = null);
    public abstract Task RemoveAsync(string? name = null, string? versionRange = null, string? kind = null);
    public abstract Task<ImmutableList<PluginInfo>> ListAsync();
}
```

With usage like:

```c#
Workspace ws = ...;
var config = await ws.Config.GetAllAsync();
await ws.Stacks.SelectAsync("foo");
await ws.Plugins.InstallAsync("aws", "2.0.0");
```

